+        ASSERT_ERROR(header_put(&headers, NULL, "Value"), EINVAL);
+        ASSERT_OK_POSITIVE(header_put(&headers, "Name", ""));
+        ASSERT_ERROR(header_put(&headers, "", "Value"), EINVAL);
+}
+
+DEFINE_TEST_MAIN(LOG_DEBUG);

