+        ALPHANUMERICAL "_ :;.,\\/'\"?!(){}[]@<>=-+*#$&`|~^%"
+
+bool header_name_is_valid(const char *e) {
+        if (isempty(e))
+                return false;
+
+        if (strlen(e) > HEADER_NAME_LENGTH_MAX)
+                return false;
+
+        return in_charset(e, VALID_HEADER_NAME_CHARS);
